import { LucideIcon } from "lucide-react";

export enum ToolCategory {
  ORGANIZE = "Organize",
  CONVERT_FROM = "Convert from PDF",
  CONVERT_TO = "Convert to PDF",
  SECURITY = "Security",
  AI = "AI & Analysis"
}

export interface ToolConfig {
  id: string;
  name: string;
  description: string;
  icon: LucideIcon;
  path: string;
  category: ToolCategory;
  acceptsMultiple: boolean;
  acceptsTypes: string; // e.g., ".pdf" or ".doc,.docx"
  color: string;
}

export interface UploadedFile {
  id: string;
  file: File;
  previewUrl?: string;
  status: 'pending' | 'processing' | 'completed' | 'error';
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

import { GoogleGenAI } from "@google/genai";

// Helper to convert file to Base64
export const fileToGenerativePart = async (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      // Remove data url prefix (e.g. "data:application/pdf;base64,")
      const base64Data = base64String.split(',')[1];
      resolve(base64Data);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const generatePDFAnalysis = async (fileBase64: string, prompt: string, apiKey: string) => {
  if (!apiKey) throw new Error("API Key is missing");

  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-preview-09-2025', // Using latest model supporting multimodal
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'application/pdf',
              data: fileBase64
            }
          },
          {
            text: prompt
          }
        ]
      },
      config: {
        systemInstruction: "You are a helpful PDF assistant. Analyze the provided document accurately. Keep responses concise unless asked for detail."
      }
    });

    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

