import React, { useCallback, useState } from 'react';
import { UploadCloud, File as FileIcon, X } from 'lucide-react';
import { ToolConfig } from '../types';

interface FileUploadProps {
  tool: ToolConfig;
  onFilesSelected: (files: File[]) => void;
}

export const FileUpload: React.FC<FileUploadProps> = ({ tool, onFilesSelected }) => {
  const [isDragging, setIsDragging] = useState(false);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      const files = Array.from(e.dataTransfer.files);
      // Basic validation based on tool.acceptsTypes could go here
      onFilesSelected(files);
    }
  }, [onFilesSelected]);

  const handleFileInput = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      onFilesSelected(Array.from(e.target.files));
    }
  }, [onFilesSelected]);

  return (
    <div 
      className={`
        relative overflow-hidden rounded-2xl border-2 border-dashed transition-all duration-300
        flex flex-col items-center justify-center p-12 text-center min-h-[300px]
        ${isDragging 
          ? 'border-brand-500 bg-brand-50 scale-[1.02]' 
          : 'border-slate-300 bg-slate-50 hover:bg-slate-100 hover:border-slate-400'
        }
      `}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
    >
      <div className={`p-4 rounded-full mb-6 ${isDragging ? 'bg-brand-100 text-brand-600' : 'bg-white text-slate-400 shadow-sm'}`}>
        <UploadCloud size={48} strokeWidth={1.5} />
      </div>

      <h3 className="text-2xl font-bold text-slate-800 mb-2">
        {isDragging ? 'Drop it here!' : 'Select PDF files'}
      </h3>
      <p className="text-slate-500 mb-8 max-w-sm">
        or drop files here. {tool.acceptsMultiple ? 'Upload multiple files.' : 'Single file upload.'}
      </p>

      <label className="relative">
        <input 
          type="file" 
          className="hidden" 
          multiple={tool.acceptsMultiple}
          accept={tool.acceptsTypes}
          onChange={handleFileInput}
        />
        <span className="
          cursor-pointer bg-brand-600 hover:bg-brand-700 text-white 
          font-bold py-4 px-12 rounded-xl text-lg shadow-lg hover:shadow-xl 
          transition-all transform hover:-translate-y-0.5
        ">
          Select {tool.acceptsTypes.replace('.', '').toUpperCase()} Files
        </span>
      </label>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ToolConfig, UploadedFile, ChatMessage } from '../types';
import { Trash2, ArrowRight, Download, RotateCw, File as FileIcon, Loader2, Send } from 'lucide-react';
import { generatePDFAnalysis, fileToGenerativePart } from '../services/geminiService';

interface ToolWorkspaceProps {
  tool: ToolConfig;
  files: UploadedFile[];
  onRemoveFile: (id: string) => void;
  onReset: () => void;
}

export const ToolWorkspace: React.FC<ToolWorkspaceProps> = ({ tool, files, onRemoveFile, onReset }) => {
  const [processing, setProcessing] = useState(false);
  const [progress, setProgress] = useState(0);
  const [completed, setCompleted] = useState(false);
  const [downloadUrl, setDownloadUrl] = useState<string | null>(null);

  // AI Chat State
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [chatInput, setChatInput] = useState('');
  const [isThinking, setIsThinking] = useState(false);

  // Initial welcome message for Chat
  useEffect(() => {
    if (tool.id === 'chat-pdf' && chatMessages.length === 0) {
      setChatMessages([{
        id: 'init',
        role: 'model',
        text: `I've analyzed ${files[0].file.name}. What would you like to know about this document?`,
        timestamp: Date.now()
      }]);
    }
  }, [tool.id, files, chatMessages.length]);

  const handleProcess = () => {
    setProcessing(true);
    setProgress(0);

    // Mock processing progress
    const interval = setInterval(() => {
      setProgress((prev) => {
        if (prev >= 100) {
          clearInterval(interval);
          setProcessing(false);
          setCompleted(true);
          // Create a dummy download link (in real app, this comes from backend)
          setDownloadUrl('#'); 
          return 100;
        }
        return prev + 5;
      });
    }, 150); // Simulate 3 seconds processing
  };

  const handleSendMessage = async () => {
    if (!chatInput.trim() || isThinking) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: chatInput,
      timestamp: Date.now()
    };

    setChatMessages(prev => [...prev, userMsg]);
    setChatInput('');
    setIsThinking(true);

    try {
      const apiKey = process.env.API_KEY; // In a real app, handle this securely
      if (!apiKey) {
         // Fallback for demo if no key
         setTimeout(() => {
           setChatMessages(prev => [...prev, {
             id: (Date.now() + 1).toString(),
             role: 'model',
             text: "I am ready to analyze this PDF, but the API Key is missing from the environment. Please configure `process.env.API_KEY` to use the Gemini 2.5 Flash model.",
             timestamp: Date.now()
           }]);
           setIsThinking(false);
         }, 1000);
         return;
      }

      const base64 = await fileToGenerativePart(files[0].file);
      const response = await generatePDFAnalysis(base64, userMsg.text, apiKey);

      setChatMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response || "I couldn't generate a response.",
        timestamp: Date.now()
      }]);

    } catch (error) {
      setChatMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Sorry, I encountered an error analyzing the document.",
        timestamp: Date.now()
      }]);
    } finally {
      setIsThinking(false);
    }
  };

  if (tool.id === 'chat-pdf') {
    return (
      <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-200 flex flex-col h-[600px]">
        <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
          <div className="flex items-center gap-2">
            <FileIcon className="text-brand-600" size={20} />
            <span className="font-medium text-slate-700 truncate max-w-[200px]">{files[0].file.name}</span>
          </div>
          <button onClick={onReset} className="text-sm text-slate-500 hover:text-brand-600">Change File</button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-4 bg-slate-50/50">
          {chatMessages.map((msg) => (
            <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`
                max-w-[80%] rounded-2xl px-5 py-3 shadow-sm
                ${msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none' 
                  : 'bg-white text-slate-700 border border-slate-200 rounded-tl-none'
                }
              `}>
                <p className="text-sm leading-relaxed whitespace-pre-wrap">{msg.text}</p>
              </div>
            </div>
          ))}
          {isThinking && (
            <div className="flex justify-start">
              <div className="bg-white text-slate-500 border border-slate-200 rounded-2xl rounded-tl-none px-5 py-3 shadow-sm flex items-center gap-2">
                <Loader2 size={16} className="animate-spin" />
                <span className="text-xs font-medium">Analyzing document...</span>
              </div>
            </div>
          )}
        </div>

        <div className="p-4 bg-white border-t border-slate-100">
          <div className="flex gap-2">
            <input 
              type="text" 
              value={chatInput}
              onChange={(e) => setChatInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Ask something about your PDF..."
              className="flex-1 border border-slate-300 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all"
            />
            <button 
              onClick={handleSendMessage}
              disabled={!chatInput.trim() || isThinking}
              className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-xl px-6 transition-colors"
            >
              <Send size={20} />
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (completed) {
    return (
      <div className="bg-white rounded-2xl shadow-xl overflow-hidden text-center p-12 animate-in fade-in duration-500">
        <div className="mx-auto w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6">
          <Download size={40} />
        </div>
        <h2 className="text-3xl font-bold text-slate-800 mb-4">Ready for Download!</h2>
        <p className="text-slate-500 mb-8">
          Your files have been processed successfully using {tool.name}.
        </p>
        <div className="flex flex-col sm:flex-row gap-4 justify-center">
          <a 
            href={downloadUrl || '#'} 
            className="inline-flex items-center justify-center gap-2 bg-brand-600 hover:bg-brand-700 text-white font-bold py-4 px-8 rounded-xl transition-all shadow-lg hover:shadow-xl hover:-translate-y-1"
            onClick={(e) => e.preventDefault()} // Prevent actual navigation in mock
          >
            <Download size={20} />
            Download File
          </a>
          <button 
            onClick={onReset}
            className="inline-flex items-center justify-center gap-2 bg-slate-100 hover:bg-slate-200 text-slate-700 font-bold py-4 px-8 rounded-xl transition-colors"
          >
            Process Another
          </button>
        </div>
      </div>
    );
  }

  if (processing) {
    return (
      <div className="bg-white rounded-2xl shadow-xl overflow-hidden p-12 text-center">
        <h3 className="text-2xl font-bold text-slate-800 mb-8">Processing your request...</h3>
        <div className="max-w-md mx-auto mb-4">
          <div className="h-4 bg-slate-100 rounded-full overflow-hidden">
            <div 
              className="h-full bg-brand-600 transition-all duration-300 ease-out"
              style={{ width: `${progress}%` }}
            />
          </div>
        </div>
        <p className="text-slate-500 font-medium">{progress}% Complete</p>
        <p className="text-slate-400 text-sm mt-4">Please wait while we work our magic.</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-200">
      <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
        <h3 className="font-bold text-slate-700 flex items-center gap-2">
          <tool.icon size={20} className="text-brand-600" />
          Selected Files ({files.length})
        </h3>
        <button onClick={onReset} className="text-brand-600 hover:text-brand-700 text-sm font-medium">
          Cancel
        </button>
      </div>

      <div className="p-6">
        <div className="space-y-3 mb-8 max-h-[300px] overflow-y-auto">
          {files.map(file => (
            <div key={file.id} className="flex items-center justify-between p-4 bg-white border border-slate-200 rounded-xl hover:border-brand-300 transition-colors group">
              <div className="flex items-center gap-4 overflow-hidden">
                <div className="w-10 h-10 bg-brand-50 rounded-lg flex items-center justify-center text-brand-600 flex-shrink-0">
                  <FileIcon size={20} />
                </div>
                <div className="min-w-0">
                  <p className="font-medium text-slate-700 truncate">{file.file.name}</p>
                  <p className="text-xs text-slate-400">{(file.file.size / 1024 / 1024).toFixed(2)} MB</p>
                </div>
              </div>
              <button 
                onClick={() => onRemoveFile(file.id)}
                className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
              >
                <Trash2 size={18} />
              </button>
            </div>
          ))}

          <div className="flex justify-center mt-4">
             <button className="text-sm text-slate-500 hover:text-brand-600 flex items-center gap-1">
                + Add more files
             </button>
          </div>
        </div>

        {/* Tool Specific Options Mock UI */}
        {tool.id === 'rotate' && (
          <div className="mb-8 p-6 bg-slate-50 rounded-xl border border-dashed border-slate-300 text-center">
            <p className="text-sm text-slate-500 mb-4">Rotation Options</p>
            <div className="flex justify-center gap-4">
              <button className="p-3 bg-white border border-slate-200 rounded-lg hover:border-brand-500 text-slate-600 hover:text-brand-600 transition-all shadow-sm">
                <RotateCw className="transform -scale-x-100" /> Left
              </button>
              <button className="p-3 bg-white border border-slate-200 rounded-lg hover:border-brand-500 text-slate-600 hover:text-brand-600 transition-all shadow-sm">
                <RotateCw /> Right
              </button>
            </div>
          </div>
        )}

        <button 
          onClick={handleProcess}
          className="w-full bg-brand-600 hover:bg-brand-700 text-white font-bold py-4 rounded-xl text-lg shadow-lg shadow-brand-600/20 hover:shadow-xl transition-all flex items-center justify-center gap-2"
        >
          {tool.name} <ArrowRight size={20} />
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { TOOLS } from '../constants';
import { FileUpload } from '../components/FileUpload';
import { ToolWorkspace } from '../components/ToolWorkspace';
import { UploadedFile } from '../types';

export const ToolPage: React.FC = () => {
  const { toolId } = useParams();
  const navigate = useNavigate();
  const tool = TOOLS.find(t => t.path === `/${toolId}`);
  const [files, setFiles] = useState<UploadedFile[]>([]);

  // Reset state when tool changes
  useEffect(() => {
    setFiles([]);
  }, [toolId]);

  if (!tool) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center">
        <h2 className="text-2xl font-bold text-slate-800">Tool not found</h2>
        <button 
          onClick={() => navigate('/')}
          className="mt-4 text-brand-600 hover:underline"
        >
          Go back home
        </button>
      </div>
    );
  }

  const handleFilesSelected = (newFiles: File[]) => {
    const uploadedFiles: UploadedFile[] = newFiles.map(f => ({
      id: Math.random().toString(36).substr(2, 9),
      file: f,
      status: 'pending'
    }));

    if (tool.acceptsMultiple) {
      setFiles(prev => [...prev, ...uploadedFiles]);
    } else {
      setFiles([uploadedFiles[0]]);
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(files.filter(f => f.id !== id));
  };

  const handleReset = () => {
    setFiles([]);
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Tool Header */}
      <div className="bg-white border-b border-slate-100 py-12 px-4 text-center">
        <h1 className="text-3xl md:text-4xl font-extrabold text-slate-800 mb-4">{tool.name}</h1>
        <p className="text-lg text-slate-500 max-w-2xl mx-auto">{tool.description}</p>
      </div>

      {/* Workspace */}
      <div className="max-w-4xl mx-auto px-4 py-12">
        {files.length === 0 ? (
          <FileUpload tool={tool} onFilesSelected={handleFilesSelected} />
        ) : (
          <ToolWorkspace 
            tool={tool} 
            files={files} 
            onRemoveFile={handleRemoveFile} 
            onReset={handleReset}
          />
        )}
      </div>

      {/* SEO Content Placeholder */}
      <div className="max-w-4xl mx-auto px-4 pb-20 text-slate-600 prose">
        <h3 className="text-xl font-bold text-slate-800 mb-4">How to use {tool.name}?</h3>
        <p>
          Processing your PDF files has never been easier. Just drag and drop your files into the box above, 
          configure your settings, and we'll handle the rest. Our servers are secure and your privacy is guaranteed.
        </p>
      </div>
    </div>
  );
};

