      if (!apiKey) {
         // Fallback for demo if no key
         setTimeout(() => {
           setChatMessages(prev => [...prev, {
             id: (Date.now() + 1).toString(),
             role: 'model',
             text: "I am ready to analyze this PDF, but the API Key is missing from the environment. Please configure `process.env.API_KEY` to use the Gemini 2.5 Flash model.",
