import { PDFDocument, degrees } from 'pdf-lib';
import JSZip from 'jszip';

export const mergePDFs = async (files: File[]): Promise<Blob> => {
  const mergedPdf = await PDFDocument.create();

  for (const file of files) {
    const arrayBuffer = await file.arrayBuffer();
    const pdf = await PDFDocument.load(arrayBuffer);
    const copiedPages = await mergedPdf.copyPages(pdf, pdf.getPageIndices());
    copiedPages.forEach((page) => mergedPdf.addPage(page));
  }

  const pdfBytes = await mergedPdf.save();
  return new Blob([pdfBytes], { type: 'application/pdf' });
};

export const splitPDF = async (file: File): Promise<Blob> => {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await PDFDocument.load(arrayBuffer);
  const zip = new JSZip();
  const folder = zip.folder("split_pages");

  const numberOfPages = pdf.getPageCount();

  for (let i = 0; i < numberOfPages; i++) {
    const newPdf = await PDFDocument.create();
    const [copiedPage] = await newPdf.copyPages(pdf, [i]);
    newPdf.addPage(copiedPage);
    const pdfBytes = await newPdf.save();

    // Pad page number with zeros
    const pageNum = (i + 1).toString().padStart(3, '0');
    folder?.file(`page_${pageNum}.pdf`, pdfBytes);
  }

  const content = await zip.generateAsync({ type: "blob" });
  return content;
};

export const rotatePDF = async (file: File, rotationAngle: number): Promise<Blob> => {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await PDFDocument.load(arrayBuffer);
  const pages = pdf.getPages();

  pages.forEach(page => {
    const currentRotation = page.getRotation().angle;
    page.setRotation(degrees(currentRotation + rotationAngle));
  });

  const pdfBytes = await pdf.save();
  return new Blob([pdfBytes], { type: 'application/pdf' });
};

import { GoogleGenAI } from "@google/genai";

// Helper to convert file to Base64
export const fileToGenerativePart = async (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      // Remove data url prefix (e.g. "data:application/pdf;base64,")
      const base64Data = base64String.split(',')[1];
      resolve(base64Data);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const generatePDFAnalysis = async (fileBase64: string, prompt: string, apiKey: string) => {
  if (!apiKey) throw new Error("API Key is missing");

  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-preview-09-2025', 
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'application/pdf',
              data: fileBase64
            }
          },
          {
            text: prompt
          }
        ]
      },
      config: {
        systemInstruction: "You are a helpful PDF assistant. Analyze the provided document accurately."
      }
    });

    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export const convertPDFToDoc = async (fileBase64: string, apiKey: string): Promise<string> => {
  if (!apiKey) throw new Error("API Key is missing for conversion");

  const ai = new GoogleGenAI({ apiKey });

  // We ask Gemini to convert the PDF content to semantic HTML, which Word opens gracefully as a doc.
  const prompt = `
    Convert the following PDF document into a clean, well-structured HTML document that simulates a Word document.
    - Preserve headings, paragraphs, lists, and tables.
    - Do not include <html>, <head>, or <body> tags, just the content body.
    - Use standard inline styles for bold, italics, etc.
    - Return ONLY the HTML code. No markdown code blocks.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-preview-09-2025', 
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'application/pdf',
              data: fileBase64
            }
          },
          {
            text: prompt
          }
        ]
      }
    });

    const htmlContent = response.text || "";
    // Wrap in a minimal word-compatible html structure
    return `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head><meta charset='utf-8'><title>Document</title></head>
      <body>${htmlContent.replace(/```html/g, '').replace(/```/g, '')}</body>
      </html>
    `;
  } catch (error) {
    console.error("Conversion Error:", error);
    throw error;
  }
};

