import { PDFDocument, degrees } from 'pdf-lib';
import JSZip from 'jszip';
import * as mammoth from 'mammoth';

export const mergePDFs = async (files: File[]): Promise<Blob> => {
  const mergedPdf = await PDFDocument.create();

  for (const file of files) {
    const arrayBuffer = await file.arrayBuffer();
    const pdf = await PDFDocument.load(arrayBuffer);
    const copiedPages = await mergedPdf.copyPages(pdf, pdf.getPageIndices());
    copiedPages.forEach((page) => mergedPdf.addPage(page));
  }

  const pdfBytes = await mergedPdf.save();
  return new Blob([pdfBytes], { type: 'application/pdf' });
};

export const splitPDF = async (file: File): Promise<Blob> => {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await PDFDocument.load(arrayBuffer);
  const zip = new JSZip();
  const folder = zip.folder("split_pages");

  const numberOfPages = pdf.getPageCount();

  for (let i = 0; i < numberOfPages; i++) {
    const newPdf = await PDFDocument.create();
    const [copiedPage] = await newPdf.copyPages(pdf, [i]);
    newPdf.addPage(copiedPage);
    const pdfBytes = await newPdf.save();

    // Pad page number with zeros
    const pageNum = (i + 1).toString().padStart(3, '0');
    folder?.file(`page_${pageNum}.pdf`, pdfBytes);
  }

  const content = await zip.generateAsync({ type: "blob" });
  return content;
};

export const rotatePDF = async (file: File, rotationAngle: number): Promise<Blob> => {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await PDFDocument.load(arrayBuffer);
  const pages = pdf.getPages();

  pages.forEach(page => {
    const currentRotation = page.getRotation().angle;
    page.setRotation(degrees(currentRotation + rotationAngle));
  });

  const pdfBytes = await pdf.save();
  return new Blob([pdfBytes], { type: 'application/pdf' });
};

export const convertWordToPDF = async (file: File): Promise<Blob> => {
  try {
    const arrayBuffer = await file.arrayBuffer();
    // Convert DOCX to HTML
    const result = await mammoth.convertToHtml({ arrayBuffer: arrayBuffer });
    const html = result.value;

    if (!html) {
      throw new Error("Could not extract content from Word document.");
    }

    // Create a temporary container for formatting
    const element = document.createElement('div');
    element.innerHTML = `
      <div style="font-family: Arial, sans-serif; line-height: 1.6; color: #333; padding: 20px; max-width: 800px; margin: 0 auto;">
        ${html}
      </div>
    `;

    // We append to body to ensure styles might render, but html2pdf can work detached.
    // However, detached elements sometimes have issues with images.
    // Let's keep it detached but ensure images work if embedded (base64).

    const options = {
      margin: 10,
      filename: file.name.replace(/\.docx?$/i, '.pdf'),
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
    };

    // Assuming html2pdf is loaded globally from index.html script tag
    // @ts-ignore
    if (typeof window.html2pdf !== 'function') {
      throw new Error("PDF generation library not loaded.");
    }

    // @ts-ignore
    const pdfBlob = await window.html2pdf().set(options).from(element).output('blob');
    return pdfBlob;

  } catch (error) {
    console.error("Word to PDF Error:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { ToolConfig, UploadedFile, ChatMessage } from '../types';
import { Trash2, ArrowRight, Download, RotateCw, File as FileIcon, Loader2, Send } from 'lucide-react';
import { generatePDFAnalysis, fileToGenerativePart, convertPDFToDoc } from '../services/geminiService';
import { mergePDFs, splitPDF, rotatePDF, convertWordToPDF } from '../services/pdfUtils';

interface ToolWorkspaceProps {
  tool: ToolConfig;
  files: UploadedFile[];
  onRemoveFile: (id: string) => void;
  onReset: () => void;
}

export const ToolWorkspace: React.FC<ToolWorkspaceProps> = ({ tool, files, onRemoveFile, onReset }) => {
  const [processing, setProcessing] = useState(false);
  const [progress, setProgress] = useState(0);
  const [completed, setCompleted] = useState(false);
  const [downloadUrl, setDownloadUrl] = useState<string | null>(null);
  const [downloadName, setDownloadName] = useState<string>('document.pdf');

  // Tool Specific State
  const [rotationAngle, setRotationAngle] = useState(0);

  // AI Chat State
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [chatInput, setChatInput] = useState('');
  const [isThinking, setIsThinking] = useState(false);

  // Initial welcome message for Chat
  useEffect(() => {
    if (tool.id === 'chat-pdf' && chatMessages.length === 0) {
      setChatMessages([{
        id: 'init',
        role: 'model',
        text: `I've analyzed ${files[0].file.name}. What would you like to know about this document?`,
        timestamp: Date.now()
      }]);
    }
  }, [tool.id, files, chatMessages.length]);

  const handleProcess = async () => {
    setProcessing(true);
    setProgress(10); // Start progress

    try {
      let resultBlob: Blob | null = null;
      let resultName = 'download.pdf';

      // Simulate progress for UX
      const progressInterval = setInterval(() => {
        setProgress(prev => Math.min(prev + 5, 90));
      }, 200);

      switch (tool.id) {
        case 'merge':
          if (files.length < 2) {
            alert("Please select at least 2 PDF files to merge.");
            setProcessing(false);
            clearInterval(progressInterval);
            return;
          }
          resultBlob = await mergePDFs(files.map(f => f.file));
          resultName = 'merged_document.pdf';
          break;

        case 'split':
          // Currently splits into individual pages zipped
          resultBlob = await splitPDF(files[0].file);
          resultName = 'split_pages.zip';
          break;

        case 'rotate':
          if (rotationAngle === 0) {
            // If no rotation selected, just return original
            resultBlob = files[0].file;
          } else {
            resultBlob = await rotatePDF(files[0].file, rotationAngle);
          }
          resultName = `rotated_${files[0].file.name}`;
          break;

        case 'pdf-to-word':
          const apiKey = process.env.API_KEY;
          if (!apiKey) {
            throw new Error("API Key is missing from configuration. Cannot perform AI conversion.");
          }
          const base64 = await fileToGenerativePart(files[0].file);
          const htmlDoc = await convertPDFToDoc(base64, apiKey);
          resultBlob = new Blob([htmlDoc], { type: 'application/msword' });
          resultName = files[0].file.name.replace(/\.pdf$/i, '.doc');
          break;

        case 'word-to-pdf':
            resultBlob = await convertWordToPDF(files[0].file);
            resultName = files[0].file.name.replace(/\.docx?$/i, '.pdf');
            break;

        default:
          // Fallback for tools not yet implemented with real logic
          console.warn(`Tool ${tool.id} logic not implemented, returning original file.`);
          resultBlob = files[0].file;
          resultName = files[0].file.name;
          break;
      }

      clearInterval(progressInterval);
      setProgress(100);

      if (resultBlob) {
        const url = URL.createObjectURL(resultBlob);
        setDownloadUrl(url);
        setDownloadName(resultName);
        setCompleted(true);
      }

    } catch (error) {
      console.error("Processing failed", error);
      alert("An error occurred: " + (error as Error).message);
      setProcessing(false);
      setProgress(0);
    } finally {
      if (completed) { 
        // Logic handled in catch/if
      } else {
         // setProcessing(false) handled in catch
      }
    }
  };

  const handleSendMessage = async () => {
    if (!chatInput.trim() || isThinking) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: chatInput,
      timestamp: Date.now()
    };

    setChatMessages(prev => [...prev, userMsg]);
    setChatInput('');
    setIsThinking(true);

    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey) {
         setTimeout(() => {
           setChatMessages(prev => [...prev, {
             id: (Date.now() + 1).toString(),
             role: 'model',
             text: "API Key is missing. Please configure `process.env.API_KEY`.",
             timestamp: Date.now()
           }]);
           setIsThinking(false);
         }, 1000);
         return;
      }

