        case 'rotate':
          if (rotationAngle === 0) {
            // If no rotation selected, just return original
            resultBlob = files[0].file;
          } else {
            resultBlob = await rotatePDF(files[0].file, rotationAngle);
          }
          resultName = `rotated_${files[0].file.name}`;
          break;

        case 'pdf-to-word':
          const apiKey = process.env.API_KEY;
          if (!apiKey) {
            throw new Error("API Key is missing from configuration. Cannot perform AI conversion.");
          }
          const base64 = await fileToGenerativePart(files[0].file);
          const htmlDoc = await convertPDFToDoc(base64, apiKey);
          resultBlob = new Blob([htmlDoc], { type: 'application/msword' });
          resultName = files[0].file.name.replace(/\.pdf$/i, '.doc');
          break;

        case 'pdf-to-excel':
          const apiKeyExcel = process.env.API_KEY;
          if (!apiKeyExcel) {
            throw new Error("API Key is missing from configuration. Cannot perform AI conversion.");
          }
          const base64Excel = await fileToGenerativePart(files[0].file);
          const xlsContent = await convertPDFToExcel(base64Excel, apiKeyExcel);
          // application/vnd.ms-excel works well for HTML-based XLS
          resultBlob = new Blob([xlsContent], { type: 'application/vnd.ms-excel' });
          resultName = files[0].file.name.replace(/\.pdf$/i, '.xls');
          break;

        case 'word-to-pdf':
            resultBlob = await convertWordToPDF(files[0].file);
            resultName = files[0].file.name.replace(/\.docx?$/i, '.pdf');
            break;

        default:
          // Fallback for tools not yet implemented with real logic
          console.warn(`Tool ${tool.id} logic not implemented, returning original file.`);
          resultBlob = files[0].file;
          resultName = files[0].file.name;
          break;
      }

      clearInterval(progressInterval);
      setProgress(100);

      if (resultBlob) {
        const url = URL.createObjectURL(resultBlob);
        setDownloadUrl(url);
        setDownloadName(resultName);
        setCompleted(true);
      }

    } catch (error) {
      console.error("Processing failed", error);
      alert("An error occurred: " + (error as Error).message);
      setProcessing(false);
      setProgress(0);
    } finally {
      if (completed) { 
        // Logic handled in catch/if
      } else {
         // setProcessing(false) handled in catch
      }
    }
  };

  const handleSendMessage = async () => {
    if (!chatInput.trim() || isThinking) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: chatInput,
      timestamp: Date.now()
    };

    setChatMessages(prev => [...prev, userMsg]);
    setChatInput('');
    setIsThinking(true);

    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey) {
         setTimeout(() => {
           setChatMessages(prev => [...prev, {
             id: (Date.now() + 1).toString(),
             role: 'model',
             text: "API Key is missing. Please configure `process.env.API_KEY`.",
             timestamp: Date.now()
           }]);
           setIsThinking(false);
         }, 1000);
         return;
      }

      const base64 = await fileToGenerativePart(files[0].file);
      const response = await generatePDFAnalysis(base64, userMsg.text, apiKey);

      setChatMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response || "I couldn't generate a response.",
        timestamp: Date.now()
      }]);

    } catch (error) {
      setChatMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Sorry, I encountered an error analyzing the document.",
        timestamp: Date.now()
      }]);
    } finally {
      setIsThinking(false);
    }
  };

  if (tool.id === 'chat-pdf') {
    return (
      <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-200 flex flex-col h-[600px]">
        <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
          <div className="flex items-center gap-2">
            <FileIcon className="text-brand-600" size={20} />
            <span className="font-medium text-slate-700 truncate max-w-[200px]">{files[0].file.name}</span>
          </div>
          <button onClick={onReset} className="text-sm text-slate-500 hover:text-brand-600">Change File</button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-4 bg-slate-50/50">
          {chatMessages.map((msg) => (
            <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`
                max-w-[80%] rounded-2xl px-5 py-3 shadow-sm
                ${msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none' 
                  : 'bg-white text-slate-700 border border-slate-200 rounded-tl-none'
                }
              `}>
                <p className="text-sm leading-relaxed whitespace-pre-wrap">{msg.text}</p>
              </div>
            </div>
          ))}
          {isThinking && (
            <div className="flex justify-start">
              <div className="bg-white text-slate-500 border border-slate-200 rounded-2xl rounded-tl-none px-5 py-3 shadow-sm flex items-center gap-2">
                <Loader2 size={16} className="animate-spin" />
                <span className="text-xs font-medium">Analyzing document...</span>
              </div>
            </div>
          )}
        </div>

        <div className="p-4 bg-white border-t border-slate-100">
          <div className="flex gap-2">
            <input 
              type="text" 
              value={chatInput}
              onChange={(e) => setChatInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Ask something about your PDF..."
              className="flex-1 border border-slate-300 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all"
            />
            <button 
              onClick={handleSendMessage}
              disabled={!chatInput.trim() || isThinking}
              className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-xl px-6 transition-colors"
            >
              <Send size={20} />
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (completed) {
    return (
      <div className="bg-white rounded-2xl shadow-xl overflow-hidden text-center p-12 animate-in fade-in duration-500">
        <div className="mx-auto w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6">
          <Download size={40} />
        </div>
        <h2 className="text-3xl font-bold text-slate-800 mb-4">Ready for Download!</h2>
        <p className="text-slate-500 mb-8">
          Your files have been processed successfully using {tool.name}.
        </p>
        <div className="flex flex-col sm:flex-row gap-4 justify-center">
          <a 
            href={downloadUrl || '#'} 
            download={downloadName}
            className="inline-flex items-center justify-center gap-2 bg-brand-600 hover:bg-brand-700 text-white font-bold py-4 px-8 rounded-xl transition-all shadow-lg hover:shadow-xl hover:-translate-y-1"
          >
            <Download size={20} />
            Download File
          </a>
          <button 
            onClick={onReset}
            className="inline-flex items-center justify-center gap-2 bg-slate-100 hover:bg-slate-200 text-slate-700 font-bold py-4 px-8 rounded-xl transition-colors"
          >
            Process Another
          </button>
        </div>
      </div>
    );
  }

  if (processing) {
    return (
      <div className="bg-white rounded-2xl shadow-xl overflow-hidden p-12 text-center">
        <h3 className="text-2xl font-bold text-slate-800 mb-8">Processing your request...</h3>
        <div className="max-w-md mx-auto mb-4">
          <div className="h-4 bg-slate-100 rounded-full overflow-hidden">
            <div 
              className="h-full bg-brand-600 transition-all duration-300 ease-out"
              style={{ width: `${progress}%` }}
            />
          </div>
        </div>
        <p className="text-slate-500 font-medium">{progress}% Complete</p>
        <p className="text-slate-400 text-sm mt-4">Please wait while we work our magic.</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-200">
      <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
        <h3 className="font-bold text-slate-700 flex items-center gap-2">
          <tool.icon size={20} className="text-brand-600" />
          Selected Files ({files.length})
        </h3>
        <button onClick={onReset} className="text-brand-600 hover:text-brand-700 text-sm font-medium">
          Cancel
        </button>
      </div>

      <div className="p-6">
        <div className="space-y-3 mb-8 max-h-[300px] overflow-y-auto">
          {files.map(file => (
            <div key={file.id} className="flex items-center justify-between p-4 bg-white border border-slate-200 rounded-xl hover:border-brand-300 transition-colors group">
              <div className="flex items-center gap-4 overflow-hidden">
                <div className="w-10 h-10 bg-brand-50 rounded-lg flex items-center justify-center text-brand-600 flex-shrink-0">
                  <FileIcon size={20} />
                </div>
                <div className="min-w-0">
                  <p className="font-medium text-slate-700 truncate">{file.file.name}</p>
                  <p className="text-xs text-slate-400">{(file.file.size / 1024 / 1024).toFixed(2)} MB</p>
                </div>
              </div>
              <button 
                onClick={() => onRemoveFile(file.id)}
                className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
              >
                <Trash2 size={18} />
              </button>
            </div>
          ))}

          <div className="flex justify-center mt-4">
             <button className="text-sm text-slate-500 hover:text-brand-600 flex items-center gap-1">
                + Add more files
             </button>
          </div>
        </div>

        {/* Tool Specific Options UI */}
        {tool.id === 'rotate' && (
          <div className="mb-8 p-6 bg-slate-50 rounded-xl border border-dashed border-slate-300 text-center">
            <p className="text-sm text-slate-500 mb-4">Rotation Options ({rotationAngle}°)</p>
            <div className="flex justify-center gap-4">
              <button 
                onClick={() => setRotationAngle((prev) => prev - 90)}
                className="p-3 bg-white border border-slate-200 rounded-lg hover:border-brand-500 text-slate-600 hover:text-brand-600 transition-all shadow-sm"
              >
                <RotateCw className="transform -scale-x-100" /> Left
              </button>
              <button 
                onClick={() => setRotationAngle((prev) => prev + 90)}
                className="p-3 bg-white border border-slate-200 rounded-lg hover:border-brand-500 text-slate-600 hover:text-brand-600 transition-all shadow-sm"
              >
                <RotateCw /> Right
              </button>
            </div>
          </div>
        )}

        {tool.id === 'split' && (
          <div className="mb-8 p-4 bg-blue-50 text-blue-800 rounded-lg text-sm text-center">
