        <button 
          onClick={handleProcess}
          className="w-full bg-brand-600 hover:bg-brand-700 text-white font-bold py-4 rounded-xl text-lg shadow-lg shadow-brand-600/20 hover:shadow-xl transition-all flex items-center justify-center gap-2"
