};

import React, { useState, useEffect, useRef } from 'react';
import { ToolConfig, UploadedFile, ChatMessage } from '../types';
import { Trash2, ArrowRight, Download, RotateCw, File as FileIcon, Loader2, Send, Sparkles, Bot, User } from 'lucide-react';
import { generatePDFAnalysis, fileToGenerativePart, convertPDFToDoc, convertPDFToExcel } from '../services/geminiService';
import { mergePDFs, splitPDF, rotatePDF, convertWordToPDF } from '../services/pdfUtils';

interface ToolWorkspaceProps {
  tool: ToolConfig;
  files: UploadedFile[];
  onRemoveFile: (id: string) => void;
  onReset: () => void;
}

export const ToolWorkspace: React.FC<ToolWorkspaceProps> = ({ tool, files, onRemoveFile, onReset }) => {
  const [processing, setProcessing] = useState(false);
  const [progress, setProgress] = useState(0);
  const [completed, setCompleted] = useState(false);
  const [downloadUrl, setDownloadUrl] = useState<string | null>(null);
  const [downloadName, setDownloadName] = useState<string>('document.pdf');
  const chatBottomRef = useRef<HTMLDivElement>(null);

  // Tool Specific State
  const [rotationAngle, setRotationAngle] = useState(0);

  // AI Chat State
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [chatInput, setChatInput] = useState('');
  const [isThinking, setIsThinking] = useState(false);

  useEffect(() => {
    if (chatBottomRef.current) {
      chatBottomRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatMessages, isThinking]);

  // Initial welcome message for Chat
  useEffect(() => {
    if (tool.id === 'chat-pdf' && chatMessages.length === 0) {
      setChatMessages([{
        id: 'init',
        role: 'model',
        text: `Hi there! I've analyzed **${files[0].file.name}**. I'm ready to summarize it, answer questions, or extract specific data for you.`,
        timestamp: Date.now()
      }]);
    }
  }, [tool.id, files, chatMessages.length]);

  const handleProcess = async () => {
    setProcessing(true);
    setProgress(10); // Start progress

    try {
      let resultBlob: Blob | null = null;
      let resultName = 'download.pdf';

      const progressInterval = setInterval(() => {
        setProgress(prev => Math.min(prev + 5, 90));
      }, 200);

      switch (tool.id) {
        case 'merge':
          if (files.length < 2) {
            alert("Please select at least 2 PDF files to merge.");
            setProcessing(false);
            clearInterval(progressInterval);
            return;
          }
          resultBlob = await mergePDFs(files.map(f => f.file));
          resultName = 'merged_document.pdf';
          break;

        case 'split':
          resultBlob = await splitPDF(files[0].file);
          resultName = 'split_pages.zip';
          break;

        case 'rotate':
          if (rotationAngle === 0) {
            resultBlob = files[0].file;
          } else {
            resultBlob = await rotatePDF(files[0].file, rotationAngle);
          }
          resultName = `rotated_${files[0].file.name}`;
          break;

        case 'pdf-to-word':
          const apiKey = process.env.API_KEY;
          if (!apiKey) throw new Error("API Key is missing.");
          const base64 = await fileToGenerativePart(files[0].file);
          const htmlDoc = await convertPDFToDoc(base64, apiKey);
          resultBlob = new Blob([htmlDoc], { type: 'application/msword' });
          resultName = files[0].file.name.replace(/\.pdf$/i, '.doc');
          break;

        case 'pdf-to-excel':
          const apiKeyExcel = process.env.API_KEY;
          if (!apiKeyExcel) throw new Error("API Key is missing.");
          const base64Excel = await fileToGenerativePart(files[0].file);
          const xlsContent = await convertPDFToExcel(base64Excel, apiKeyExcel);
          resultBlob = new Blob([xlsContent], { type: 'application/vnd.ms-excel' });
          resultName = files[0].file.name.replace(/\.pdf$/i, '.xls');
          break;

        case 'word-to-pdf':
            resultBlob = await convertWordToPDF(files[0].file);
            resultName = files[0].file.name.replace(/\.docx?$/i, '.pdf');
            break;

        default:
          console.warn(`Tool ${tool.id} logic not implemented, returning original file.`);
          resultBlob = files[0].file;
          resultName = files[0].file.name;
          break;
      }

      clearInterval(progressInterval);
      setProgress(100);

      if (resultBlob) {
        const url = URL.createObjectURL(resultBlob);
        setDownloadUrl(url);
        setDownloadName(resultName);
        setTimeout(() => setCompleted(true), 500); // Small delay for progress bar finish
      }

    } catch (error) {
      console.error("Processing failed", error);
      alert("An error occurred: " + (error as Error).message);
      setProcessing(false);
      setProgress(0);
    }
  };

  const handleSendMessage = async () => {
    if (!chatInput.trim() || isThinking) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: chatInput,
      timestamp: Date.now()
    };

    setChatMessages(prev => [...prev, userMsg]);
    setChatInput('');
    setIsThinking(true);

    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey) {
         setTimeout(() => {
           setChatMessages(prev => [...prev, {
             id: (Date.now() + 1).toString(),
             role: 'model',
             text: "API Key is missing. Please configure `process.env.API_KEY`.",
             timestamp: Date.now()
           }]);
           setIsThinking(false);
         }, 1000);
         return;
      }

      const base64 = await fileToGenerativePart(files[0].file);
      const response = await generatePDFAnalysis(base64, userMsg.text, apiKey);

      setChatMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response || "I couldn't generate a response.",
        timestamp: Date.now()
      }]);

    } catch (error) {
      setChatMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Sorry, I encountered an error analyzing the document.",
        timestamp: Date.now()
      }]);
    } finally {
      setIsThinking(false);
    }
  };

  if (tool.id === 'chat-pdf') {
    return (
      <div className="bg-white rounded-3xl shadow-2xl shadow-slate-200/50 overflow-hidden border border-white flex flex-col h-[700px] animate-fade-in">
        <div className="p-4 border-b border-slate-100 bg-white/80 backdrop-blur-sm z-10 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-100 text-indigo-600 p-2 rounded-xl">
              <Sparkles size={20} />
            </div>
            <div>
              <h3 className="font-bold text-slate-800">AI Assistant</h3>
              <p className="text-xs text-slate-500 truncate max-w-[200px]">Analyzing: {files[0].file.name}</p>
            </div>
          </div>
          <button onClick={onReset} className="text-sm px-3 py-1.5 rounded-lg text-slate-500 hover:bg-slate-100 transition-colors">Change File</button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50">
          {chatMessages.map((msg) => (
            <div key={msg.id} className={`flex items-start gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''} animate-slide-up`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${msg.role === 'user' ? 'bg-slate-900 text-white' : 'bg-indigo-600 text-white'}`}>
                {msg.role === 'user' ? <User size={14} /> : <Bot size={16} />}
              </div>
              <div className={`
                max-w-[80%] rounded-2xl px-6 py-4 shadow-sm text-sm leading-relaxed
                ${msg.role === 'user' 
                  ? 'bg-slate-900 text-white rounded-tr-sm' 
                  : 'bg-white text-slate-700 rounded-tl-sm border border-slate-100'
                }
              `}>
                <p className="whitespace-pre-wrap">{msg.text}</p>
              </div>
            </div>
          ))}
          {isThinking && (
            <div className="flex items-center gap-3 animate-pulse">
              <div className="w-8 h-8 rounded-full bg-indigo-600 flex items-center justify-center text-white">
                 <Bot size={16} />
              </div>
              <div className="bg-white border border-slate-100 px-4 py-3 rounded-2xl rounded-tl-sm shadow-sm flex items-center gap-2">
                <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></span>
                <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{animationDelay: '0.2s'}}></span>
                <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{animationDelay: '0.4s'}}></span>
              </div>
            </div>
          )}
          <div ref={chatBottomRef} />
        </div>

        <div className="p-4 bg-white border-t border-slate-100">
          <div className="relative">
            <input 
              type="text" 
              value={chatInput}
              onChange={(e) => setChatInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Ask me anything about this document..."
              className="w-full bg-slate-50 border border-slate-200 rounded-2xl pl-6 pr-14 py-4 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all"
            />
            <button 
              onClick={handleSendMessage}
              disabled={!chatInput.trim() || isThinking}
              className="absolute right-2 top-2 p-2.5 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 disabled:bg-slate-300 text-white rounded-xl transition-all shadow-md hover:shadow-lg"
            >
              <Send size={18} />
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (completed) {
    return (
      <div className="bg-white rounded-[2rem] shadow-2xl shadow-brand-900/10 overflow-hidden text-center p-12 animate-fade-in border border-white relative">
        <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-green-400 to-brand-500"></div>

        <div className="mx-auto w-24 h-24 bg-green-50 text-green-500 rounded-full flex items-center justify-center mb-8 animate-bounce">
          <Download size={48} />
        </div>
        <h2 className="font-display text-4xl font-bold text-slate-900 mb-4">It's Ready!</h2>
        <p className="text-slate-500 mb-10 text-lg">
          Your file has been processed and is ready for download.
        </p>
        <div className="flex flex-col sm:flex-row gap-4 justify-center">
          <a 
            href={downloadUrl || '#'} 
            download={downloadName}
            className="inline-flex items-center justify-center gap-2 bg-slate-900 hover:bg-slate-800 text-white font-bold py-4 px-10 rounded-xl transition-all shadow-xl hover:shadow-2xl hover:-translate-y-1"
          >
            <Download size={20} />
            Download Now
          </a>
          <button 
            onClick={onReset}
            className="inline-flex items-center justify-center gap-2 bg-slate-100 hover:bg-slate-200 text-slate-700 font-bold py-4 px-8 rounded-xl transition-colors"
          >
            Start Over
          </button>
        </div>
      </div>
    );
  }

  if (processing) {
    return (
      <div className="bg-white rounded-[2rem] shadow-2xl shadow-brand-900/10 overflow-hidden p-16 text-center animate-fade-in border border-white">
        <h3 className="font-display text-3xl font-bold text-slate-900 mb-10">Processing...</h3>

        <div className="relative w-48 h-48 mx-auto mb-8">
           {/* Circular Progress Indicator Simulation */}
           <svg className="w-full h-full transform -rotate-90">
             <circle cx="96" cy="96" r="88" stroke="#f1f5f9" strokeWidth="12" fill="none" />
             <circle 
               cx="96" cy="96" r="88" 
               stroke="#e11d48" 
               strokeWidth="12" 
               fill="none" 
               strokeDasharray="553" 
               strokeDashoffset={553 - (553 * progress) / 100} 
               className="transition-all duration-300 ease-out"
               strokeLinecap="round"
             />
           </svg>
           <div className="absolute inset-0 flex items-center justify-center">
             <span className="text-4xl font-bold text-slate-800">{progress}%</span>
           </div>
        </div>

        <p className="text-slate-500 font-medium">Just a moment while we {tool.name.toLowerCase()} your file.</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-[2rem] shadow-xl shadow-slate-200/50 overflow-hidden border border-white animate-fade-in">
      <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-white">
        <h3 className="font-display text-2xl font-bold text-slate-800 flex items-center gap-3">
          <div className="bg-brand-50 text-brand-600 p-2 rounded-lg">
            <tool.icon size={24} />
          </div>
          Files Selected <span className="text-slate-400 text-lg font-normal">({files.length})</span>
        </h3>
        <button onClick={onReset} className="text-brand-600 hover:text-brand-700 font-medium hover:underline">
          Cancel & Reset
        </button>
      </div>

      <div className="p-8">
        <div className="space-y-4 mb-10 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
          {files.map(file => (
            <div key={file.id} className="flex items-center justify-between p-5 bg-slate-50 border border-slate-100 rounded-2xl hover:border-brand-200 transition-colors group">
              <div className="flex items-center gap-5 overflow-hidden">
                <div className="w-14 h-14 bg-white rounded-xl flex items-center justify-center text-brand-600 shadow-sm border border-slate-100 flex-shrink-0">
                  <FileIcon size={28} />
                </div>
                <div className="min-w-0">
                  <p className="font-bold text-slate-800 text-lg truncate mb-1">{file.file.name}</p>
                  <p className="text-sm text-slate-500 font-medium">{(file.file.size / 1024 / 1024).toFixed(2)} MB</p>
                </div>
              </div>
              <button 
                onClick={() => onRemoveFile(file.id)}
                className="p-3 text-slate-400 hover:text-red-500 hover:bg-white rounded-xl transition-all"
              >
                <Trash2 size={20} />
              </button>
            </div>
          ))}

          <button className="w-full py-4 border-2 border-dashed border-slate-200 rounded-2xl text-slate-400 font-medium hover:border-brand-300 hover:text-brand-600 hover:bg-brand-50/30 transition-all">
             + Add more files
          </button>
        </div>

        {/* Tool Specific Options UI */}
        {tool.id === 'rotate' && (
          <div className="mb-10 p-8 bg-slate-50 rounded-3xl border border-slate-100 text-center">
            <p className="text-slate-500 font-medium mb-6">Rotation Options <span className="font-bold text-brand-600">({rotationAngle}°)</span></p>
            <div className="flex justify-center gap-6">
              <button 
                onClick={() => setRotationAngle((prev) => prev - 90)}
                className="flex flex-col items-center gap-2 p-4 bg-white border border-slate-200 rounded-2xl hover:border-brand-500 hover:shadow-lg text-slate-600 hover:text-brand-600 transition-all w-32"
              >
                <RotateCw className="transform -scale-x-100" size={28} /> 
                <span className="font-bold">Left</span>
              </button>
              <button 
                onClick={() => setRotationAngle((prev) => prev + 90)}
                className="flex flex-col items-center gap-2 p-4 bg-white border border-slate-200 rounded-2xl hover:border-brand-500 hover:shadow-lg text-slate-600 hover:text-brand-600 transition-all w-32"
              >
                <RotateCw size={28} /> 
                <span className="font-bold">Right</span>
              </button>
            </div>
          </div>
        )}

        <button 
          onClick={handleProcess}
          className="w-full bg-slate-900 hover:bg-slate-800 text-white font-display font-bold text-xl py-6 rounded-2xl shadow-xl shadow-slate-900/20 hover:shadow-2xl hover:-translate-y-1 transition-all flex items-center justify-center gap-3 group"
        >
          {tool.name} <ArrowRight size={24} className="group-hover:translate-x-1 transition-transform" />
        </button>
      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

// Helper to convert file to Base64
export const fileToGenerativePart = async (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      // Remove data url prefix (e.g. "data:application/pdf;base64,")
      const base64Data = base64String.split(',')[1];
      resolve(base64Data);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const generatePDFAnalysis = async (fileBase64: string, prompt: string, apiKey: string) => {
  if (!apiKey) throw new Error("API Key is missing");

  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-preview-09-2025', 
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'application/pdf',
              data: fileBase64
            }
          },
          {
            text: prompt
          }
        ]
      },
      config: {
        systemInstruction: "You are a helpful PDF assistant. Analyze the provided document accurately."
      }
    });

    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export const convertPDFToDoc = async (fileBase64: string, apiKey: string): Promise<string> => {
  if (!apiKey) throw new Error("API Key is missing for conversion");

  const ai = new GoogleGenAI({ apiKey });

  // We ask Gemini to convert the PDF content to semantic HTML, which Word opens gracefully as a doc.
  const prompt = `
    Convert the following PDF document into a clean, well-structured HTML document that simulates a Word document.
    - Preserve headings, paragraphs, lists, and tables.
    - Do not include <html>, <head>, or <body> tags, just the content body.
    - Use standard inline styles for bold, italics, etc.
    - Return ONLY the HTML code. No markdown code blocks.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-preview-09-2025', 
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'application/pdf',
              data: fileBase64
            }
          },
          {
            text: prompt
          }
        ]
      }
    });

    const htmlContent = response.text || "";
    // Wrap in a minimal word-compatible html structure
    return `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head><meta charset='utf-8'><title>Document</title></head>
      <body>${htmlContent.replace(/```html/g, '').replace(/```/g, '')}</body>
      </html>
    `;
  } catch (error) {
    console.error("Conversion Error:", error);
    throw error;
  }
};

export const convertPDFToExcel = async (fileBase64: string, apiKey: string): Promise<string> => {
  if (!apiKey) throw new Error("API Key is missing for conversion");

  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    Extract all tabular data from the following PDF document.
    - Output the data as valid HTML <table> structures.
    - Preserve column headers.
    - Do not include any other text, just the tables.
    - If there are multiple tables, separate them with <br><br>.
    - Return ONLY the HTML code. No markdown code blocks.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-preview-09-2025', 
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'application/pdf',
              data: fileBase64
            }
          },
          {
            text: prompt
          }
        ]
      }
    });

    const htmlContent = response.text || "";

    // Wrap in a minimal HTML structure compatible with Excel
    // This allows the file to be opened by Excel as an .xls file
    return `
      <html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">
      <head>
        <meta http-equiv="content-type" content="application/vnd.ms-excel; charset=UTF-8"/>
      </head>
      <body>${htmlContent.replace(/```html/g, '').replace(/```/g, '')}</body>
      </html>
    `;
  } catch (error) {
    console.error("Conversion Error:", error);
    throw error;
  }
};

export const convertJPGToWordOCR = async (fileBase64: string, mimeType: string, apiKey: string): Promise<string> => {
  if (!apiKey) throw new Error("API Key is missing for OCR conversion");

  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    Perform high-fidelity OCR on this image. 
    1. Reconstruct the document structure exactly as seen (headings, paragraphs, lists, tables).
    2. Format the output as clean, semantic HTML that is compatible with Microsoft Word.
    3. Do not include <html>, <head>, or <body> tags in your initial response, just the inner content.
    4. Return ONLY the HTML code. No conversational text. No Markdown blocks.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-preview-09-2025', 
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: fileBase64
            }
          },
          {
            text: prompt
          }
        ]
      }
    });

    const htmlContent = response.text || "";

    return `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head><meta charset='utf-8'><title>OCR Document</title></head>
      <body>${htmlContent.replace(/```html/g, '').replace(/```/g, '')}</body>
      </html>
    `;
  } catch (error) {
    console.error("OCR Conversion Error:", error);
    throw error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { ToolConfig, UploadedFile, ChatMessage } from '../types';
import { Trash2, ArrowRight, Download, RotateCw, File as FileIcon, Loader2, Send, Sparkles, Bot, User } from 'lucide-react';
import { generatePDFAnalysis, fileToGenerativePart, convertPDFToDoc, convertPDFToExcel, convertJPGToWordOCR } from '../services/geminiService';
import { mergePDFs, splitPDF, rotatePDF, convertWordToPDF } from '../services/pdfUtils';

interface ToolWorkspaceProps {
  tool: ToolConfig;
  files: UploadedFile[];
  onRemoveFile: (id: string) => void;
  onReset: () => void;
}

export const ToolWorkspace: React.FC<ToolWorkspaceProps> = ({ tool, files, onRemoveFile, onReset }) => {
  const [processing, setProcessing] = useState(false);
  const [progress, setProgress] = useState(0);
  const [completed, setCompleted] = useState(false);
  const [downloadUrl, setDownloadUrl] = useState<string | null>(null);
  const [downloadName, setDownloadName] = useState<string>('document.pdf');
  const chatBottomRef = useRef<HTMLDivElement>(null);

  // Tool Specific State
  const [rotationAngle, setRotationAngle] = useState(0);

  // AI Chat State
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [chatInput, setChatInput] = useState('');
  const [isThinking, setIsThinking] = useState(false);

  useEffect(() => {
    if (chatBottomRef.current) {
      chatBottomRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatMessages, isThinking]);

  // Initial welcome message for Chat
  useEffect(() => {
    if (tool.id === 'chat-pdf' && chatMessages.length === 0) {
      setChatMessages([{
        id: 'init',
        role: 'model',
        text: `Hi there! I've analyzed **${files[0].file.name}**. I'm ready to summarize it, answer questions, or extract specific data for you.`,
        timestamp: Date.now()
      }]);
    }
  }, [tool.id, files, chatMessages.length]);

  const handleProcess = async () => {
    setProcessing(true);
    setProgress(10); // Start progress

    try {
      let resultBlob: Blob | null = null;
      let resultName = 'download.pdf';

      const progressInterval = setInterval(() => {
        setProgress(prev => Math.min(prev + 5, 90));
      }, 200);

      switch (tool.id) {
        case 'merge':
          if (files.length < 2) {
            alert("Please select at least 2 PDF files to merge.");
            setProcessing(false);
            clearInterval(progressInterval);
            return;
          }
          resultBlob = await mergePDFs(files.map(f => f.file));
          resultName = 'merged_document.pdf';
          break;

        case 'split':
          resultBlob = await splitPDF(files[0].file);
          resultName = 'split_pages.zip';
          break;

        case 'rotate':
          if (rotationAngle === 0) {
            resultBlob = files[0].file;
          } else {
            resultBlob = await rotatePDF(files[0].file, rotationAngle);
          }
          resultName = `rotated_${files[0].file.name}`;
          break;

        case 'pdf-to-word': {
          const apiKey = process.env.API_KEY;
          if (!apiKey) throw new Error("API Key is missing.");
          const base64 = await fileToGenerativePart(files[0].file);
          const htmlDoc = await convertPDFToDoc(base64, apiKey);
          resultBlob = new Blob([htmlDoc], { type: 'application/msword' });
          resultName = files[0].file.name.replace(/\.pdf$/i, '.doc');
          break;
        }

        case 'jpg-to-word': {
          const apiKey = process.env.API_KEY;
          if (!apiKey) throw new Error("API Key is missing.");
          const file = files[0].file;
          const base64 = await fileToGenerativePart(file);
          const htmlDoc = await convertJPGToWordOCR(base64, file.type, apiKey);
          resultBlob = new Blob([htmlDoc], { type: 'application/msword' });
          resultName = file.name.replace(/\.(jpg|jpeg|png)$/i, '.doc');
          break;
        }

        case 'pdf-to-excel': {
          const apiKeyExcel = process.env.API_KEY;
          if (!apiKeyExcel) throw new Error("API Key is missing.");
          const base64Excel = await fileToGenerativePart(files[0].file);
          const xlsContent = await convertPDFToExcel(base64Excel, apiKeyExcel);
          resultBlob = new Blob([xlsContent], { type: 'application/vnd.ms-excel' });
          resultName = files[0].file.name.replace(/\.pdf$/i, '.xls');
          break;
        }

        case 'word-to-pdf':
            resultBlob = await convertWordToPDF(files[0].file);
            resultName = files[0].file.name.replace(/\.docx?$/i, '.pdf');
            break;

        default:
          console.warn(`Tool ${tool.id} logic not implemented, returning original file.`);
          resultBlob = files[0].file;
          resultName = files[0].file.name;
          break;
      }

      clearInterval(progressInterval);
      setProgress(100);

      if (resultBlob) {
        const url = URL.createObjectURL(resultBlob);
        setDownloadUrl(url);
        setDownloadName(resultName);
        setTimeout(() => setCompleted(true), 500); // Small delay for progress bar finish
      }

    } catch (error) {
      console.error("Processing failed", error);
      alert("An error occurred: " + (error as Error).message);
      setProcessing(false);
      setProgress(0);
    }
  };

  const handleSendMessage = async () => {
    if (!chatInput.trim() || isThinking) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: chatInput,
      timestamp: Date.now()
    };

    setChatMessages(prev => [...prev, userMsg]);
    setChatInput('');
    setIsThinking(true);

    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey) {
         setTimeout(() => {
           setChatMessages(prev => [...prev, {
             id: (Date.now() + 1).toString(),
             role: 'model',
             text: "API Key is missing. Please configure `process.env.API_KEY`.",
             timestamp: Date.now()
           }]);
           setIsThinking(false);
         }, 1000);
         return;
      }

      const base64 = await fileToGenerativePart(files[0].file);
      const response = await generatePDFAnalysis(base64, userMsg.text, apiKey);

      setChatMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response || "I couldn't generate a response.",
        timestamp: Date.now()
      }]);

    } catch (error) {
      setChatMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Sorry, I encountered an error analyzing the document.",
        timestamp: Date.now()
      }]);
    } finally {
      setIsThinking(false);
    }
  };

  if (tool.id === 'chat-pdf') {
    return (
