                   {msg.text}
                </div>
             </div>
           ))}
           {isThinking && <div className="text-sm text-slate-400 animate-pulse flex items-center gap-2"><Loader2 size={14} className="animate-spin" /> Thinking...</div>}
           <div ref={chatBottomRef} />
        </div>
        <div className="p-4 border-t flex gap-2">
