import React, { useState, useEffect, useRef } from 'react';
import { ToolConfig, UploadedFile, ChatMessage } from '../types';
import { Trash2, ArrowRight, Download, RotateCw, File as FileIcon, Loader2, Send, Sparkles, Bot, User, Crop, Type, Hash, Code, AlertCircle } from 'lucide-react';
import { generatePDFAnalysis, fileToGenerativePart, convertPDFToDoc, convertPDFToExcel, convertJPGToWordOCR, convertOfficeToHtml, cleanWatermark } from '../services/geminiService';
import { mergePDFs, splitPDF, rotatePDF, convertWordToPDF, imagesToPDF, pdfToImages, addWatermark, addPageNumbers, cropPDF, repairPDF } from '../services/pdfUtils';
import * as XLSX from 'xlsx';

interface ToolWorkspaceProps {
  tool: ToolConfig;
  files: UploadedFile[];
  onRemoveFile: (id: string) => void;
  onReset: () => void;
}

export const ToolWorkspace: React.FC<ToolWorkspaceProps> = ({ tool, files, onRemoveFile, onReset }) => {
  const [processing, setProcessing] = useState(false);
  const [progress, setProgress] = useState(0);
  const [completed, setCompleted] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [downloadUrl, setDownloadUrl] = useState<string | null>(null);
  const [downloadName, setDownloadName] = useState<string>('document.pdf');

  const [rotationAngle, setRotationAngle] = useState(0);
  const [watermarkText, setWatermarkText] = useState('CONFIDENTIAL');
  const [htmlInput, setHtmlInput] = useState('');

  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [chatInput, setChatInput] = useState('');
  const [isThinking, setIsThinking] = useState(false);
  const chatBottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (chatBottomRef.current) {
      chatBottomRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatMessages, isThinking]);

  useEffect(() => {
    if (tool.id === 'chat-pdf' && chatMessages.length === 0) {
      setChatMessages([{
        id: 'init',
        role: 'model',
        text: `I've analyzed **${files[0].file.name}**. What would you like to know?`,
        timestamp: Date.now()
      }]);
    }
  }, [tool.id, files, chatMessages.length]);

  const handleProcess = async () => {
    setProcessing(true);
    setError(null);
    setProgress(10); 

    try {
      let resultBlob: Blob | null = null;
      let resultName = 'download.pdf';

      const progressInterval = setInterval(() => {
        setProgress(prev => Math.min(prev + 5, 90));
      }, 300);

      switch (tool.id) {
        case 'merge':
          resultBlob = await mergePDFs(files.map(f => f.file));
          resultName = 'merged_document.pdf';
          break;
        case 'split':
          resultBlob = await splitPDF(files[0].file);
          resultName = 'split_pages.zip';
          break;
        case 'rotate':
          resultBlob = await rotatePDF(files[0].file, rotationAngle);
          resultName = `rotated_${files[0].file.name}`;
          break;
        case 'crop':
          resultBlob = await cropPDF(files[0].file);
          resultName = `cropped_${files[0].file.name}`;
          break;
        case 'repair':
          resultBlob = await repairPDF(files[0].file);
          resultName = `repaired_${files[0].file.name}`;
          break;
        case 'add-watermark':
          resultBlob = await addWatermark(files[0].file, watermarkText);
          resultName = `watermarked_${files[0].file.name}`;
          break;
        case 'page-numbers':
          resultBlob = await addPageNumbers(files[0].file);
          resultName = `numbered_${files[0].file.name}`;
          break;
        case 'jpg-to-pdf':
          resultBlob = await imagesToPDF(files.map(f => f.file));
          resultName = 'images_combined.pdf';
          break;
        case 'pdf-to-jpg':
          resultBlob = await pdfToImages(files[0].file);
          resultName = 'pdf_images.zip';
          break;
        case 'word-to-pdf':
          resultBlob = await convertWordToPDF(files[0].file);
          resultName = files[0].file.name.replace(/\.docx?$/i, '.pdf');
          break;
        case 'html-to-pdf': {
          let content = htmlInput || (files.length > 0 ? await files[0].file.text() : '');
          if (!content) throw new Error("No HTML content provided.");
          const element = document.createElement('div');
          element.innerHTML = content;
          // @ts-ignore
          resultBlob = await window.html2pdf().set({ margin: 10 }).from(element).output('blob');
          resultName = 'webpage.pdf';
          break;
        }
        case 'pdf-to-word': {
          const base64 = await fileToGenerativePart(files[0].file);
          const htmlDoc = await convertPDFToDoc(base64);
          resultBlob = new Blob([htmlDoc], { type: 'application/msword' });
          resultName = files[0].file.name.replace(/\.pdf$/i, '.doc');
          break;
        }
        case 'pdf-to-excel': {
          const base64 = await fileToGenerativePart(files[0].file);
          const jsonData = await convertPDFToExcel(base64);
          const wb = XLSX.utils.book_new();
          (jsonData.tables || []).forEach((t: any, i: number) => {
            const ws = XLSX.utils.aoa_to_sheet(t.rows);
            XLSX.utils.book_append_sheet(wb, ws, t.name || `Table ${i+1}`);
          });
          const buffer = XLSX.write(wb, { bookType: 'xlsx', type: 'array' });
          resultBlob = new Blob([buffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
          resultName = files[0].file.name.replace(/\.pdf$/i, '.xlsx');
          break;
        }
        case 'jpg-to-word':
        case 'ocr-to-pdf': {
          const base64 = await fileToGenerativePart(files[0].file);
          const html = await convertJPGToWordOCR(base64, files[0].file.type);
          if (tool.id === 'ocr-to-pdf') {
            const el = document.createElement('div'); el.innerHTML = html;
            // @ts-ignore
            resultBlob = await window.html2pdf().from(el).output('blob');
            resultName = files[0].file.name + '.pdf';
          } else {
            resultBlob = new Blob([html], { type: 'application/msword' });
            resultName = files[0].file.name + '.doc';
          }
          break;
        }
        case 'remove-watermark': {
          const base64 = await fileToGenerativePart(files[0].file);
          const clean = await cleanWatermark(base64);
          const el = document.createElement('div'); el.innerHTML = clean;
          // @ts-ignore
          resultBlob = await window.html2pdf().from(el).output('blob');
          resultName = 'clean_' + files[0].file.name;
          break;
        }
        default:
          resultBlob = files[0].file;
          resultName = files[0].file.name;
      }

      clearInterval(progressInterval);
      setProgress(100);

      if (resultBlob) {
        setDownloadUrl(URL.createObjectURL(resultBlob));
        setDownloadName(resultName);
        setTimeout(() => setCompleted(true), 500);
      }
    } catch (err: any) {
      setError(err.message || "An unexpected error occurred during processing.");
      setProcessing(false);
    }
  };

  const handleSendMessage = async () => {
    if (!chatInput.trim() || isThinking) return;
    const msg: ChatMessage = { id: Date.now().toString(), role: 'user', text: chatInput, timestamp: Date.now() };
    setChatMessages(prev => [...prev, msg]);
    setChatInput('');
    setIsThinking(true);
    try {
      const base64 = await fileToGenerativePart(files[0].file);
      const res = await generatePDFAnalysis(base64, msg.text);
      setChatMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: res || "I couldn't generate a response.", timestamp: Date.now() }]);
    } catch (err: any) {
      setChatMessages(prev => [...prev, { id: 'err', role: 'model', text: "Error: " + err.message, timestamp: Date.now() }]);
    } finally {
      setIsThinking(false);
    }
  };

  if (tool.id === 'chat-pdf') {
    return (
      <div className="bg-white rounded-3xl shadow-xl flex flex-col h-[650px] border border-slate-100 overflow-hidden">
        <div className="p-4 border-b flex justify-between bg-slate-50 items-center">
          <div className="flex items-center gap-2 font-bold text-slate-800">
            <Sparkles size={18} className="text-indigo-600 animate-pulse"/> AI Assistant
          </div>
          <button onClick={onReset} className="text-xs font-bold text-slate-400 hover:text-slate-600 uppercase tracking-wider">Change File</button>
        </div>
        <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
          {chatMessages.map(m => (
            <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed ${m.role === 'user' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'bg-slate-100 text-slate-700'}`}>
                {m.text}
              </div>
            </div>
          ))}
          {isThinking && <div className="text-xs text-slate-400 flex items-center gap-2 italic"><Loader2 size={12} className="animate-spin" /> Analyzing document...</div>}
          <div ref={chatBottomRef} />
        </div>
        <div className="p-4 bg-white border-t flex gap-2">
          <input value={chatInput} onChange={e => setChatInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleSendMessage()} className="flex-1 border border-slate-200 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-indigo-100 outline-none transition-all" placeholder="Type your question..." />
          <button onClick={handleSendMessage} disabled={isThinking} className="bg-indigo-600 hover:bg-indigo-700 text-white p-3 rounded-xl transition-all disabled:opacity-50"><Send size={20}/></button>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-white rounded-3xl shadow-xl p-12 text-center animate-fade-in border border-red-50">
        <div className="mx-auto w-16 h-16 bg-red-100 text-red-500 rounded-full flex items-center justify-center mb-6"><AlertCircle size={32}/></div>
        <h2 className="text-xl font-bold mb-4 text-slate-800">Processing Error</h2>
        <p className="text-slate-500 mb-8 text-sm max-w-sm mx-auto">{error}</p>
        <button onClick={() => { setError(null); setProcessing(false); }} className="bg-slate-900 text-white font-bold py-3 px-8 rounded-xl hover:bg-slate-800 transition-all">Try Again</button>
      </div>
    );
  }

  if (completed) {
    return (
      <div className="bg-white rounded-3xl shadow-xl p-12 text-center animate-fade-in">
        <div className="mx-auto w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6"><Download size={40}/></div>
        <h2 className="text-3xl font-bold mb-4 text-slate-800">Success!</h2>
        <p className="text-slate-500 mb-8">File processed successfully. Download below.</p>
        <a href={downloadUrl || '#'} download={downloadName} className="inline-flex items-center gap-2 bg-slate-900 text-white font-bold py-4 px-10 rounded-2xl hover:shadow-2xl transition-all">
          <Download size={20} /> Download Result
        </a>
        <button onClick={onReset} className="block mt-6 mx-auto text-slate-400 hover:text-slate-600 font-bold text-sm uppercase tracking-widest">New Task</button>
      </div>
    );
  }

  if (processing) {
    return (
      <div className="bg-white rounded-3xl shadow-xl p-16 text-center animate-fade-in">
        <div className="mx-auto w-24 h-24 mb-8 relative">
          <svg className="w-full h-full transform -rotate-90">
            <circle cx="48" cy="48" r="42" stroke="currentColor" strokeWidth="6" fill="transparent" className="text-slate-50" />
            <circle cx="48" cy="48" r="42" stroke="currentColor" strokeWidth="6" fill="transparent" strokeDasharray={263.8} strokeDashoffset={263.8 - (263.8 * progress) / 100} className="text-brand-500 transition-all duration-300" strokeLinecap="round" />
          </svg>
          <div className="absolute inset-0 flex items-center justify-center font-bold text-lg text-slate-700">{progress}%</div>
        </div>
        <h3 className="text-xl font-bold text-slate-800 mb-2">Processing Document...</h3>
        <p className="text-slate-400 text-sm">Our AI is hard at work on your file.</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-100 animate-fade-in">
      <div className="p-8 border-b border-slate-50 flex justify-between items-center">
        <h3 className="text-xl font-bold text-slate-800 flex items-center gap-3">
          <div className={`p-2 rounded-lg text-white ${tool.color}`}><tool.icon size={20} /></div>
          {tool.name}
        </h3>
        <button onClick={onReset} className="text-slate-400 hover:text-slate-600 transition-colors"><Trash2 size={18} /></button>
      </div>
      <div className="p-8">
        <div className="space-y-3 mb-8">
          {files.map(f => (
            <div key={f.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100 group">
              <div className="flex items-center gap-4">
                <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-brand-500 shadow-sm"><FileIcon size={20} /></div>
                <div>
                  <span className="font-bold text-slate-700 block text-sm truncate max-w-[250px]">{f.file.name}</span>
                  <span className="text-[10px] text-slate-400 font-bold uppercase">{(f.file.size / 1024 / 1024).toFixed(2)} MB</span>
                </div>
              </div>
              <button onClick={() => onRemoveFile(f.id)} className="p-2 text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={18} /></button>
            </div>
          ))}
        </div>

        {tool.id === 'rotate' && (
          <div className="mb-8 p-6 bg-slate-50 rounded-2xl border border-slate-100">
            <p className="text-center text-[10px] font-bold text-slate-400 uppercase mb-4 tracking-widest">Rotation Angle</p>
            <div className="flex justify-center items-center gap-8">
              <button onClick={() => setRotationAngle(a => a - 90)} className="p-4 bg-white rounded-xl border border-slate-200 hover:border-brand-500 transition-all"><RotateCw className="-scale-x-100" size={20}/></button>
              <span className="text-2xl font-bold text-slate-800 w-16 text-center">{rotationAngle}°</span>
              <button onClick={() => setRotationAngle(a => a + 90)} className="p-4 bg-white rounded-xl border border-slate-200 hover:border-brand-500 transition-all"><RotateCw size={20}/></button>
            </div>
          </div>
        )}

        {tool.id === 'add-watermark' && (
          <div className="mb-8">
            <label className="text-[10px] font-bold text-slate-400 uppercase mb-2 block tracking-widest">Watermark Text</label>
            <input type="text" value={watermarkText} onChange={e => setWatermarkText(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:bg-white outline-none transition-all" />
          </div>
        )}

        {tool.id === 'html-to-pdf' && (
          <div className="mb-8">
            <label className="text-[10px] font-bold text-slate-400 uppercase mb-2 block tracking-widest">Source HTML</label>
            <textarea value={htmlInput} onChange={e => setHtmlInput(e.target.value)} className="w-full h-32 bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:bg-white outline-none transition-all font-mono text-xs" placeholder="Paste your HTML code here..." />
          </div>
        )}

        <button onClick={handleProcess} className="w-full bg-slate-900 hover:bg-slate-800 text-white font-bold py-5 rounded-2xl shadow-xl shadow-slate-900/10 hover:shadow-2xl transition-all flex items-center justify-center gap-3">
          Process Now <ArrowRight size={20} />
        </button>
      </div>
    </div>
  );
};
